32	export function parsePort(raw: string, fallback: number): number {
33	  const trimmed = raw.trim();
34	  if (!trimmed) {
35	    return fallback;
36	  }
37	  const parsed = Number.parseInt(trimmed, 10);
38	  if (!Number.isFinite(parsed) || parsed < 1 || parsed > 65535) {
39	    return fallback;
40	  }
41	  return parsed;
42	}
