import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { isBoardTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

function makePulseBoardMessageId(): string {
  return `pb-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
}

export function resolvePulseBoardInboundTarget(params: {
  target: string;
  senderHandle: string;
}): {
  isGroup: boolean;
  target: string;
} {
  const isGroup = isBoardTarget(params.target);
  if (isGroup) {
    return { isGroup: true, target: params.target };
  }
  const senderHandle = params.senderHandle.trim();
  return { isGroup: false, target: senderHandle || params.target };
}

/**
 * Connect to the PulseBoard streaming API and listen for inbound messages.
 * Returns a handle to stop the monitor.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl and apiToken in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let aborted = false;

  // Poll the PulseBoard events endpoint for new messages.
  const pollIntervalMs = 3000;
  let pollTimer: ReturnType<typeof setInterval> | null = null;

  async function poll(): Promise<void> {
    if (aborted) {
      return;
    }
    try {
      const response = await fetch(
        `${account.apiUrl}/events?boards=${encodeURIComponent((account.config.boards ?? []).join(","))}`,
        {
          method: "GET",
          headers: {
            Authorization: `Bearer ${account.config.apiToken}`,
            Accept: "application/json",
          },
          signal: opts.abortSignal,
        },
      );
      if (!response.ok) {
        logger.error(`[${account.accountId}] PulseBoard poll error: HTTP ${response.status}`);
        return;
      }
      const events = (await response.json()) as Array<{
        id: string;
        target: string;
        senderHandle: string;
        senderDisplayName?: string;
        text: string;
        timestamp: number;
        boardName?: string;
      }>;
      for (const event of events) {
        if (aborted) {
          break;
        }
        // Skip messages sent by the bot itself.
        if (event.senderHandle === account.displayName) {
          continue;
        }

        const inboundTarget = resolvePulseBoardInboundTarget({
          target: event.target,
          senderHandle: event.senderHandle,
        });
        const message: PulseBoardInboundMessage = {
          messageId: event.id || makePulseBoardMessageId(),
          target: inboundTarget.target,
          senderHandle: event.senderHandle,
          senderDisplayName: event.senderDisplayName,
          text: event.text,
          timestamp: event.timestamp || Date.now(),
          isGroup: inboundTarget.isGroup,
          boardName: event.boardName,
        };

        core.channel.activity.record({
          channel: "pulseboard",
          accountId: account.accountId,
          direction: "inbound",
          at: message.timestamp,
        });

        if (opts.onMessage) {
          await opts.onMessage(message);
        }
      }
    } catch (err) {
      if (!aborted) {
        const msg = err instanceof Error ? err.message : String(err);
        logger.error(`[${account.accountId}] PulseBoard poll error: ${msg}`);
      }
    }
  }

  // Start polling.
  pollTimer = setInterval(() => void poll(), pollIntervalMs);
  // Run an initial poll immediately.
  void poll();

  logger.info(
    `[${account.accountId}] connected to PulseBoard at ${account.apiUrl} as ${account.displayName}`,
  );

  opts.abortSignal?.addEventListener("abort", () => {
    aborted = true;
    if (pollTimer) {
      clearInterval(pollTimer);
      pollTimer = null;
    }
  });

  return {
    stop: () => {
      aborted = true;
      if (pollTimer) {
        clearInterval(pollTimer);
        pollTimer = null;
      }
    },
  };
}

